import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import api from '../utils/api';
import { toast } from 'react-toastify';

/* ── Tag input used inside the edit modal ── */
function TagInput({ label, values = [], onChange }) {
  const [input, setInput] = useState('');
  const add = () => {
    const v = input.trim();
    if (v && !values.includes(v)) onChange([...values, v]);
    setInput('');
  };
  const remove = (item) => onChange(values.filter((x) => x !== item));
  return (
    <div>
      <label className="form-label fw-semibold" style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>{label}</label>
      <div className="d-flex gap-2 mb-1">
        <input
          className="form-control form-control-sm"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), add())}
          placeholder="Type and press Enter"
        />
        <button type="button" className="btn btn-sm btn-outline-primary px-3" onClick={add}>Add</button>
      </div>
      <div className="d-flex flex-wrap gap-1 mt-1">
        {values.map((v) => (
          <span key={v} className="badge d-flex align-items-center gap-1"
            style={{ background: 'var(--primary-light)', color: 'var(--primary)', fontWeight: 500, fontSize: '0.75rem', padding: '4px 8px' }}>
            {v}
            <button type="button" className="btn-close ms-1" style={{ fontSize: 8, filter: 'none', opacity: 0.6 }} onClick={() => remove(v)} />
          </span>
        ))}
      </div>
    </div>
  );
}

/* ── Small helper to render a labelled info row ── */
function InfoRow({ icon, label, value }) {
  if (!value && value !== 0) return null;
  return (
    <div className="d-flex align-items-start gap-3 py-2" style={{ borderBottom: '1px solid var(--border)' }}>
      <div style={{ width: 32, height: 32, borderRadius: 8, background: 'var(--primary-light)',
        display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
        <i className={`bi ${icon}`} style={{ color: 'var(--primary)', fontSize: '0.9rem' }} />
      </div>
      <div>
        <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.04em' }}>{label}</div>
        <div style={{ fontSize: '0.9rem', color: 'var(--text)', fontWeight: 500, marginTop: 1 }}>{value}</div>
      </div>
    </div>
  );
}

/* ── Tag display row ── */
function TagRow({ icon, label, values = [] }) {
  if (!values.length) return null;
  return (
    <div className="d-flex align-items-start gap-3 py-2" style={{ borderBottom: '1px solid var(--border)' }}>
      <div style={{ width: 32, height: 32, borderRadius: 8, background: 'var(--primary-light)',
        display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
        <i className={`bi ${icon}`} style={{ color: 'var(--primary)', fontSize: '0.9rem' }} />
      </div>
      <div>
        <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.04em' }}>{label}</div>
        <div className="d-flex flex-wrap gap-1 mt-1">
          {values.map((v) => (
            <span key={v} className="badge"
              style={{ background: 'var(--primary-light)', color: 'var(--primary)', fontWeight: 500, fontSize: '0.75rem', padding: '3px 8px' }}>
              {v}
            </span>
          ))}
        </div>
      </div>
    </div>
  );
}

/* ── Edit Modal ── */
function EditProfileModal({ user, onClose, onSaved }) {
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({
    name: user?.name || '',
    phone: user?.phone || '',
    address: user?.address || '',
    age: user?.age || '',
    gender: user?.gender || '',
    bloodGroup: user?.bloodGroup || '',
    emergencyContact: user?.emergencyContact || '',
    specialization: user?.specialization || '',
    licenseNumber: user?.licenseNumber || '',
    experience: user?.experience || '',
    allergies: user?.allergies || [],
    chronicDiseases: user?.chronicDiseases || [],
    pastSurgeries: user?.pastSurgeries || [],
    currentMedications: user?.currentMedications || [],
    familyHistory: user?.familyHistory || '',
  });

  const set = (field) => (e) => setForm((f) => ({ ...f, [field]: e.target.value }));
  const setArr = (field) => (val) => setForm((f) => ({ ...f, [field]: val }));

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.name.trim()) return toast.error('Name is required');
    setLoading(true);
    try {
      const res = await api.put(`/users/${user._id || user.id}`, form);
      toast.success('Profile updated successfully');
      onSaved(res.data.user);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Update failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      {/* Backdrop */}
      <div onClick={onClose}
        style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.45)', zIndex: 1040,
          animation: 'fadeIn 0.2s ease' }} />

      {/* Modal */}
      <div style={{ position: 'fixed', inset: 0, zIndex: 1050, overflowY: 'auto',
        display: 'flex', alignItems: 'flex-start', justifyContent: 'center', padding: '2rem 1rem' }}>
        <div style={{ background: 'var(--surface)', borderRadius: 16, width: '100%', maxWidth: 620,
          boxShadow: '0 20px 60px rgba(0,0,0,0.2)', animation: 'slideUp 0.25s ease' }}>

          {/* Header */}
          <div className="d-flex align-items-center justify-content-between px-4 py-3"
            style={{ borderBottom: '1px solid var(--border)' }}>
            <div className="d-flex align-items-center gap-2">
              <i className="bi bi-pencil-square" style={{ color: 'var(--primary)', fontSize: '1.1rem' }} />
              <span style={{ fontWeight: 700, fontSize: '1rem' }}>Edit Profile</span>
            </div>
            <button type="button" className="btn-close" onClick={onClose} />
          </div>

          {/* Body */}
          <form onSubmit={handleSubmit}>
            <div className="px-4 py-3">
              <div className="row g-3">
                <div className="col-md-6">
                  <label className="form-label">Full Name *</label>
                  <input className="form-control" value={form.name} onChange={set('name')} required />
                </div>
                <div className="col-md-6">
                  <label className="form-label">Phone</label>
                  <input className="form-control" value={form.phone} onChange={set('phone')} placeholder="+1 234 567 8900" />
                </div>
                <div className="col-12">
                  <label className="form-label">Address</label>
                  <input className="form-control" value={form.address} onChange={set('address')} placeholder="123 Main St, City" />
                </div>

                {user?.role === 'patient' && (
                  <>
                    <div className="col-md-4">
                      <label className="form-label">Age</label>
                      <input type="number" className="form-control" value={form.age} onChange={set('age')} min={0} max={150} />
                    </div>
                    <div className="col-md-4">
                      <label className="form-label">Gender</label>
                      <select className="form-select" value={form.gender} onChange={set('gender')}>
                        <option value="">Select</option>
                        <option value="male">Male</option>
                        <option value="female">Female</option>
                        <option value="other">Other</option>
                      </select>
                    </div>
                    <div className="col-md-4">
                      <label className="form-label">Blood Group</label>
                      <select className="form-select" value={form.bloodGroup} onChange={set('bloodGroup')}>
                        <option value="">Select</option>
                        {['A+','A-','B+','B-','AB+','AB-','O+','O-'].map((g) => (
                          <option key={g} value={g}>{g}</option>
                        ))}
                      </select>
                    </div>
                    <div className="col-md-6">
                      <label className="form-label">Emergency Contact</label>
                      <input className="form-control" value={form.emergencyContact} onChange={set('emergencyContact')} />
                    </div>

                    <div className="col-12">
                      <div style={{ fontWeight: 700, fontSize: '0.85rem', color: 'var(--text-muted)',
                        textTransform: 'uppercase', letterSpacing: '0.05em', margin: '4px 0 8px' }}>
                        Medical History
                      </div>
                    </div>
                    <div className="col-md-6">
                      <TagInput label="Allergies" values={form.allergies} onChange={setArr('allergies')} />
                    </div>
                    <div className="col-md-6">
                      <TagInput label="Chronic Diseases" values={form.chronicDiseases} onChange={setArr('chronicDiseases')} />
                    </div>
                    <div className="col-md-6">
                      <TagInput label="Past Surgeries" values={form.pastSurgeries} onChange={setArr('pastSurgeries')} />
                    </div>
                    <div className="col-md-6">
                      <TagInput label="Current Medications" values={form.currentMedications} onChange={setArr('currentMedications')} />
                    </div>
                    <div className="col-12">
                      <label className="form-label">Family History</label>
                      <textarea className="form-control" rows={2} value={form.familyHistory} onChange={set('familyHistory')}
                        placeholder="e.g. Diabetes in father, hypertension in mother" />
                    </div>
                  </>
                )}

                {(user?.role === 'doctor' || user?.role === 'admin') && (
                  <>
                    <div className="col-md-6">
                      <label className="form-label">Specialization</label>
                      <input className="form-control" value={form.specialization} onChange={set('specialization')} />
                    </div>
                    <div className="col-md-3">
                      <label className="form-label">License No.</label>
                      <input className="form-control" value={form.licenseNumber} onChange={set('licenseNumber')} />
                    </div>
                    <div className="col-md-3">
                      <label className="form-label">Experience (yrs)</label>
                      <input type="number" className="form-control" value={form.experience} onChange={set('experience')} min={0} />
                    </div>
                  </>
                )}
              </div>
            </div>

            {/* Footer */}
            <div className="d-flex justify-content-end gap-2 px-4 py-3"
              style={{ borderTop: '1px solid var(--border)' }}>
              <button type="button" className="btn btn-outline-secondary" onClick={onClose}>Cancel</button>
              <button type="submit" className="btn btn-primary px-4" disabled={loading}>
                {loading
                  ? <><span className="spinner-border spinner-border-sm me-2" />Saving...</>
                  : <><i className="bi bi-check2 me-2" />Save Changes</>}
              </button>
            </div>
          </form>
        </div>
      </div>

      <style>{`
        @keyframes fadeIn { from { opacity: 0 } to { opacity: 1 } }
        @keyframes slideUp { from { opacity: 0; transform: translateY(24px) } to { opacity: 1; transform: translateY(0) } }
      `}</style>
    </>
  );
}
